package genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.service;
import genxsolution.vms.vmsbackend.vehicle_management.exception.VehicleResourceNotFoundException; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.dto.*; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.mapper.VehicleOperatingCostMapper; import genxsolution.vms.vmsbackend.vehicle_management.vehicle_operating_cost.repository.VehicleOperatingCostRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class VehicleOperatingCostService { private final VehicleOperatingCostRepository repository; private final VehicleOperatingCostMapper mapper; public VehicleOperatingCostService(VehicleOperatingCostRepository repository,VehicleOperatingCostMapper mapper){this.repository=repository;this.mapper=mapper;} public List<VehicleOperatingCostResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public VehicleOperatingCostResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleOperatingCost", id.toString())); } public VehicleOperatingCostResponse create(VehicleOperatingCostUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public VehicleOperatingCostResponse update(UUID id,VehicleOperatingCostUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new VehicleResourceNotFoundException("VehicleOperatingCost", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new VehicleResourceNotFoundException("VehicleOperatingCost", id.toString()); } }
